Stumbled upon this last night, just isolated it.
So there is a divide by zero error, which results in 'bXXXX. this triggers an infinite loop. 
No warning or output, iverilog returns non-zero
```verilog
// Icarus Verilog version 13.0 (devel) (s20221226-524-gdc6f9f204-dirty)
`default_nettype none
module bug_report_1146 ( clk, out );
    input   wire    clk;
    output  wire    out;

    function automatic integer iterator_NaryRecursionVectorSize;
        input integer base, lut_width, rt;   
        iterator_NaryRecursionVectorSize=
            base==1
                ?rt
                :iterator_NaryRecursionVectorSize(
                    base / lut_width * lut_width == base
                        ? base / lut_width
                        : base / lut_width + 1
                    ,lut_width
                    ,rt + ((base / lut_width * lut_width == base)
                        ? base / lut_width
                        : (base / lut_width) + 1));
    endfunction

    // find the size of the vector needed
    localparam STRUCTURE_SIZE = iterator_NaryRecursionVectorSize(5, 0, 0);
    assign out = 1'b0;
endmodule

module mux_tb;
    reg     clk = 0;
    wire    out;

    bug_report_1146 UUT( .clk(clk), .out(out) );
    
    always #1 clk <= ~clk;

endmodule
```

